import React, {useRef} from 'react';
import Compact from "antd/es/space/Compact";

function FCom(props) {

    const myRef = useRef();

    return (
        <div>
            <Compact>
                <input ref={myRef}/>
                <button onClick={() => {
                    alert(myRef.current.value)
                }}>获取input内容
                </button>
            </Compact>
        </div>
    );
}

export default FCom;
